mapper.select:
SELECT p.id, p.title, p.price, p.status, p.created_at, c.name AS category_name, (SELECT COUNT(*) FROM appointments a WHERE a.product_id = p.id) AS appointment_count FROM products p JOIN categories c ON c.id = p.category_id WHERE p.is_deleted = FALSE AND p.seller_id = #{sellerId}
AND p.status = #{status}
ORDER BY p.created_at DESC
